const body = $input.item.json.body || $input.item.json;
const message = body.message || body;
const call = message.call || message;

// Only process end-of-call events
const eventType = message.type || body.type || '';
if (!['end-of-call-report', 'call-end', 'end'].some(t => eventType.includes(t))) {
  return [];
}

// Extract transcript
const artifact = message.artifact || {};
const transcript = artifact.transcript || message.transcript || call.transcript || '';

// Must have meaningful transcript
if (!transcript || transcript.length < 50) {
  return [];
}

// Extract ended reason — skip very short/failed calls
const endedReason = call.endedReason || message.endedReason || '';
if (['failed', 'error'].includes(endedReason)) {
  return [];
}

// Call metadata
const callId       = call.id || message.callId || '';
const durationSecs = call.duration || artifact.duration || 0;
const startedAt    = call.startedAt || new Date().toISOString();

return [{ json: { transcript, callId, durationSecs, startedAt, endedReason } }];

