const raw = $input.item.json.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  // Strip markdown code fences if present
  const clean = raw.replace(/```json\n?/gi, '').replace(/```/gi, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { name:'', phone:'', email:'', industry:'Other', inquiry:'Web widget call', urgency:'cold', score_reason:'Parse error', booked:false };
}

const callMeta = $('Parse Call Data').item.json;

return [{ json: {
  ...parsed,
  transcript:   callMeta.transcript,
  callId:       callMeta.callId,
  durationSecs: callMeta.durationSecs,
  startedAt:    callMeta.startedAt,
  source:       'web_widget'
} }];

const lead = $('Parse GPT Response').item.json;
const urgency = lead.urgency || '';
if (urgency === 'hot') {
  return [{ json: lead }];
}
return [];

const lead = $('Parse GPT Response').item.json;
const urgency = lead.urgency || '';
if (urgency === 'warm') {
  return [{ json: lead }];
}
return [];

const lead = $('Parse GPT Response').item.json;
// Only trigger SMS drip if we captured a phone number
if (!lead.phone || lead.phone.trim() === '') {
  return [];
}
return [{ json: lead }];

